def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            base = np.exp(ratio / (bin_cap + 1)) * np.tanh(ratio)
            for a in range(1, 5):
                for b in range(1, a + 4):
                    factor = (ratio ** a) / ((b + 0.5) ** 2) * np.cos(ratio * b / (a + 0.7))
                    priority += base * factor * np.sin(bin_cap / (b + 1))
            priority += np.sqrt(np.abs(np.sin(ratio * bin_cap))) * 15
            if i % 2 == 0:
                priority -= np.log1p(bin_cap) * np.exp(-ratio / 5)
            else:
                priority += np.log1p(item) * np.sin(ratio)
        elif 4 < ratio <= 7:
            s = 0
            for m in range(1, 20):
                term = ((ratio - 4) ** 2) / (m + 0.1) * np.cos(m * ratio)
                s += np.tanh(term) * np.exp(-m / 10)
            priority = s * (np.sin(bin_cap) + 1.5)
            if bin_cap < item * 1.5:
                priority += np.sqrt(item * bin_cap) * np.tanh(ratio)
            else:
                priority -= np.log(bin_cap + 1) * 3
            for n in range(1, 6):
                priority += (ratio / (n + 1)) * np.sin(n * item * 0.8) * 0.75
        elif 2 <= ratio <= 4:
            sum_val = 0
            for k in range(1, 15):
                val = ((ratio - 2) ** k) / (k ** 1.3 + 0.5)
                sum_val += val * np.cos(k * ratio * 2)
            priority = sum_val - np.log(ratio + 1) * 8 + np.sin(bin_cap * 0.7) * 3
            if bin_cap > item * 2:
                priority -= np.exp(-ratio * 0.9) * 5
            else:
                priority += np.sqrt(item / (bin_cap + 0.1)) * 4
            for idx2 in range(1, 5):
                priority += np.sin(idx2 * ratio * i) * ((ratio - 1.9) ** idx2) / idx2
        elif 1.0 <= ratio < 2:
            pval = 0
            for t in range(1, 18):
                pval += ((2 - ratio) ** t) / (t * 2.2) * np.sin(t * bin_cap)
            if bin_cap < item * 0.9:
                penalty = np.log1p(item * bin_cap) * 6
            else:
                penalty = np.cos(15 * ratio) * 4
            priority = pval + penalty + np.exp(-2 / (ratio + 0.1))
            for w in range(1, 7):
                priority += np.sin(w * ratio * i * 0.9) * ((ratio - 1.0) ** w) / (w ** 1.1 + 0.3)
        elif 0.5 <= ratio < 1.0:
            temp_sum = 0
            for v in range(1, 12):
                temp_sum += ((1.0 - ratio) ** v) / (v ** 2 + 1) * np.cos(v * item * 1.5)
            if (i + int(item * 2)) % 5 == 0:
                priority = temp_sum * np.log1p(bin_cap + 4) * 1.8
            else:
                priority = temp_sum / (np.sqrt(bin_cap + 2) + 1.5)
            if bin_cap < item * 0.7:
                priority += np.sqrt(item * bin_cap) * 5
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for z in range(1, 8):
                priority += ((1.0 - ratio) ** z) * np.sin(z * item * 1.1) * 0.6
        elif 0.2 <= ratio < 0.5:
            val2 = 0
            for x in range(1, 14):
                val2 += ((0.5 - ratio) ** x) / (x * 3) * np.cos(x * bin_cap * 0.8)
            priority = val2 + 1 / (bin_cap + 2)
            if int(item * 1.7) % 3 == 0:
                priority *= 2.8
            else:
                priority /= 2.8
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 3.5
            else:
                priority -= np.exp(-ratio * 1.7) * 3.8
            for y in range(1, 6):
                priority += ((0.5 - ratio) ** y) / (y * 5) * np.sin(y * item * 1.3)
        else:
            residual = 0
            for q in range(1, 10):
                residual += ((0.2 - ratio) ** q) / (q * 6) * np.cos(q * item * 0.85)
            priority = residual + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 0:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 4.7
            else:
                priority -= np.exp(-ratio * 2.3) * 4.2
            for r in range(1, 9):
                priority += ((0.2 - ratio) ** r) / (r * 8) * np.sin(item * r * 0.75)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 2 * bin_cap) * 6.2
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx3 in range(1, 5):
            if (i + idx3) % 4 == 0:
                priority += np.cos(ratio * (i + idx3) * 1.1) * 0.4
            else:
                priority -= np.sin(ratio * (i + idx3) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.cos(ratio * i * 1.2) * 0.7
        else:
            priority -= np.sin(ratio * i * 1.2) * 0.7
        priorities[i] = priority
    return priorities
